+            distinct_nodes: 1,
+            ..test_coverage(4, 16)
+        };
+
+        let mild_action = controller.estimate_plan_action(
+            object_id,
+            &mildly_degraded,
+            &policy,
+            &object_meta,
+            RepairReasonCode::PolicySloDeficit,
+            &baseline_options,
+        );
+        let severe_action = controller.estimate_plan_action(
+            object_id,
+            &badly_degraded,
+            &policy,
+            &object_meta,
+            RepairReasonCode::PolicySloDeficit,
+            &baseline_options,
+        );
